
import { poolInstance as pool } from "@/lib/db";
import * as XLSX from "xlsx";
import fs from "fs";
import path from "path";
import nodemailer from "nodemailer";

function splitEmails(raw?: string) {
  if (!raw) return [];
  return raw.split(/[\n,;]+/g).map((x) => x.trim()).filter(Boolean);
}

function todayYMDInGuayaquil() {
  return new Intl.DateTimeFormat("en-CA", {
    timeZone: "America/Guayaquil",
    year: "numeric",
    month: "2-digit",
    day: "2-digit",
  }).format(new Date());
}

function nowStampGuayaquil() {
  const d = new Date();
  const date = todayYMDInGuayaquil();
  const time = new Intl.DateTimeFormat("en-GB", {
    timeZone: "America/Guayaquil",
    hour: "2-digit",
    minute: "2-digit",
    second: "2-digit",
    hour12: false,
  })
    .format(d)
    .replace(/:/g, "-");
  return `${date}_${time}`; // 2026-01-22_21-03-10
}

async function sendMail(fileName: string, buffer: Buffer) {
  const to = splitEmails(process.env.REPORT_EMAILS);
  if (!to.length) return;

  const transporter = nodemailer.createTransport({
    host: process.env.SMTP_HOST,
    port: Number(process.env.SMTP_PORT),
    secure: String(process.env.SMTP_SECURE) === "true",
    auth: { user: process.env.SMTP_USER, pass: process.env.SMTP_PASS },
  });

  await transporter.sendMail({
    from: process.env.SMTP_FROM || process.env.SMTP_USER,
    to,
    subject: `Reporte diario ${fileName}`,
    text: "Adjunto reporte diario.",
    attachments: [{ filename: fileName, content: buffer }],
  });
}

export async function generateDailyReport(opts: {
  reportDateYMD?: string;
  mode?: "auto" | "manual";
}) {
  const mode = opts.mode ?? "auto";
  const incoming = (opts.reportDateYMD || "").trim();

  // ✅ fecha SIEMPRE válida
  const reportDateYMD = /^\d{4}-\d{2}-\d{2}$/.test(incoming)
    ? incoming
    : todayYMDInGuayaquil();

  const client = await pool.connect();
  try {
    const { rows } = await client.query(`
      SELECT
        numero_prestamo,
        nombre_cliente,
        telefono_cliente,
        valor_deuda,
        valor_recaudado,
        producto,
        segmento,
        fecha_cobro,
        estado_pago,
        collection_account
      FROM public.cliente
      ORDER BY numero_prestamo DESC
    `);

    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, XLSX.utils.json_to_sheet(rows), "Detalle");

    // ✅ guardar en public/reports
    const reportsDir = path.join(process.cwd(), "public", "reports");
    fs.mkdirSync(reportsDir, { recursive: true });

    // ✅ manual no se sobreescribe
    const suffix = mode === "manual" ? `_${nowStampGuayaquil()}` : "";
    const fileName = `reporte_clientes_${reportDateYMD}${suffix}.xlsx`;
    const filePath = path.join(reportsDir, fileName);

    const buffer = XLSX.write(wb, { type: "buffer", bookType: "xlsx" });
    fs.writeFileSync(filePath, buffer);

    const publicUrl = `/reports/${fileName}`;

    // ✅ BD: auto = upsert por día / manual = insert nuevo
    if (mode === "auto") {
      await client.query(
        `
        INSERT INTO public.reportes_diarios (report_date, file_name, file_path)
        VALUES ($1::date, $2, $3)
        ON CONFLICT (report_date)
        DO UPDATE SET file_name = EXCLUDED.file_name, file_path = EXCLUDED.file_path
        `,
        [reportDateYMD, fileName, publicUrl]
      );
    } else {
      await client.query(
        `
        INSERT INTO public.reportes_diarios (report_date, file_name, file_path)
        VALUES ($1::date, $2, $3)
        `,
        [reportDateYMD, fileName, publicUrl]
      );
    }

    await sendMail(fileName, buffer);

    return { reportDateYMD, fileName, url: publicUrl };
  } finally {
    client.release();
  }
}
